protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: Cosmos DB indexing is managed via container indexing policy, not EF Core.
    // EF Core 9 throws InvalidOperationException if HasIndex is used with Cosmos.

    // Preserve legacy discriminator property name ("Discriminator" instead of new default "$type")
    // so existing documents remain readable without a data migration.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Preserve legacy compound id format ("Blog|1") so existing documents remain accessible.
    // EF Core 9 defaults to key-only ids (e.g. "1").
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
}

